import type {ForeignSessionPageHandlerRemote} from 'chrome://resources/cr_components/history/foreign_sessions.mojom-webui.js';
import {ForeignSessionPageCallbackRouter, ForeignSessionPageHandler} from 'chrome://resources/cr_components/history/foreign_sessions.mojom-webui.js';

// TODO(crbug.com/495832119): Get rid of this class, and use the mojo
// autogenerated one instead. This will require declaring a
// ForeignSessionPageHandlerFactory in the mojom file.
export interface ForeignSessionBrowserProxy {
  handler: ForeignSessionPageHandlerRemote;
  callbackRouter: ForeignSessionPageCallbackRouter;
}

export class ForeignSessionBrowserProxyImpl implements
    ForeignSessionBrowserProxy {
  handler: ForeignSessionPageHandlerRemote;
  callbackRouter: ForeignSessionPageCallbackRouter;

  constructor() {
    this.handler = ForeignSessionPageHandler.getRemote();
    this.callbackRouter = new ForeignSessionPageCallbackRouter();
    this.handler.setPage(this.callbackRouter.$.bindNewPipeAndPassRemote());
  }

  static getInstance(): ForeignSessionBrowserProxy {
    return instance || (instance = new ForeignSessionBrowserProxyImpl());
  }

  static setInstance(obj: ForeignSessionBrowserProxy) {
    instance = obj;
  }
}

let instance: ForeignSessionBrowserProxy|null = null;
